    20→/** @file*/
    21→
    22→#include "internal_nn_math.h"
    23→#include "riscv_nn_support.h"
    24→
    25→//// Convolution Functions
    26→
    27→int32_t riscv_nn_conv_HWC_s8_s8_s8_RGB_sft_bias_fast(const q7_t * in_tensor,
    28→                                    const uint16_t in_tensor_dim,
    29→                                    const q7_t * ker_weight,
    30→                                    const uint16_t out_tensor_ch,
    31→                                    const uint16_t ker_dim,
    32→                                    const uint16_t pad,
    33→                                    const uint16_t stride,
    34→                                    const q7_t * bias,
    35→                                    const uint16_t bias_lshift,
    36→                                    const uint16_t out_rshift,
    37→                                    q7_t * out_tensor,
    38→                                    const uint16_t out_tensor_dim,
    39→                                    q15_t * in_tmp_buf,
    40→                                    q15_t * wt_tmp_buf)
    41→{
    42→#ifdef ENA_EMPTY_FUN
    43→    //empty body
    44→#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
    45→    long   i_out_y, i_out_x, i_ker_y, i_ker_x;
    46→
    47→    /*
    48→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
    49→     *  im2col are done to output in q15_t format from q7_t input
    50→     */
    51→    q7_t *pBuffer = (q7_t *)in_tmp_buf;
    52→    q7_t *pOut = out_tensor;
    53→
    54→    long buf_len = (3 * ker_dim * ker_dim + 1);
    55→    long vl;
    56→
    57→    // This part implements the im2col function
    58→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    59→    {
    60→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
    61→        {
    62→            //init in_tmp_buf
    63→            uint32_t len = buf_len;
    64→            q7_t *pBuffer2 = pBuffer;
    65→            vl = __riscv_vsetvl_e8m1(len);
    66→            vint8m1_t vZero = __riscv_vand(__riscv_vundefined_i8m1(), 0, vl);   //zero
    67→            while(len > 0)
    68→            {
    69→                __riscv_vse8(pBuffer2, vZero, vl);
    70→                len -= vl;
    71→                pBuffer2 += vl;
    72→                vl = __riscv_vsetvl_e8m1(len);
    73→            }
    74→
    75→            // if (i_ker_y < 0)
    76→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
    77→            {
    78→                pBuffer += ker_dim * 3;
    79→            }
    80→
    81→            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim)? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
    82→            for (; i_ker_y < bound_y; i_ker_y++)
    83→            {
    84→                // if (i_ker_x < 0)
    85→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
    86→                {
    87→                    pBuffer += 3;
    88→                }
    89→
    90→                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim)? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
    91→                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
    92→                long loop = (bound_x - i_ker_x)*3;
    93→                i_ker_x = bound_x;
    94→                while(loop > 0)
    95→                {
    96→                    vl = __riscv_vsetvl_e8m1(loop);
    97→                    vint8m1_t vpPixel = __riscv_vle8_v_i8m1(pPixel, vl);
    98→                    __riscv_vse8(pBuffer, vpPixel, vl);
    99→                    pPixel += vl;
   100→                    pBuffer += vl;
   101→                    loop -= vl;
   102→                }
   103→
   104→                // if (i_ker_x >= in_tensor_dim)
   105→                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
   106→                {
   107→                    pBuffer += 3;
   108→                }
   109→            }
   110→
   111→            // if (i_ker_y >= in_tensor_dim)
   112→            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
   113→            {
   114→                pBuffer += ker_dim * 3;
   115→            }
   116→
   117→            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
   118→            {
   119→                pOut = nn_mat_mul_kernel_q7((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, bias_lshift, out_rshift, bias, pOut);
   120→                pBuffer = (q7_t *)in_tmp_buf;
   121→            }
   122→        }
   123→    }
   124→
   125→#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
   126→    if (pBuffer != (q7_t *)in_tmp_buf)
   127→    {
   128→        unsigned vl;
   129→        const q7_t *p_wt = ker_weight;
   130→        int       i;
   131→        uint16_t  colCnt = 3 * ker_dim * ker_dim;
   132→        // long vlenb = NDS_VEC_CSR_GET_VLENB();
   133→
   134→        vl = __riscv_vsetvl_e32m1(1);
   135→        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum
   136→
   137→        for (i = 0; i < out_tensor_ch; i++)
   138→        {
   139→            q7_t      *p_in = (q7_t*)in_tmp_buf;
   140→            uint16_t colCnt2 = colCnt;
   141→
   142→            //clear v0~v7
   143→            vl = __riscv_vsetvl_e32m8(colCnt);
   144→            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
   145→
   146→            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
   147→            // {
   148→            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
   149→            //     //load src1
   150→            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
   151→            //     //load src2
   152→            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
   153→            //     //bump pointers and update loop counter
   154→            //     colCnt2 -= vl;
   155→            //     p_wt += vl;
   156→            //     p_in += vl;
   157→            //     //set the proper avl/SEW/LMUL values for vd4dot
   158→            //     vl >>= 2;
   159→            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
   160→            //     //acc += src1 * src2
   161→            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
   162→            // }
   163→
   164→            //extra process for the case of vd4dot's avl is not a mutiple of 4
   165→            while(colCnt2 > 0)
   166→            {
   167→                //clean one of the dot product source
   168→                vl = __riscv_vsetvlmax_e8m8();
   169→                vint8m8_t vP_wt_i8 = __riscv_vand(__riscv_vundefined_i8m8(), 0, vl);
   170→
   171→                vl = __riscv_vsetvl_e8m8(colCnt2);
   172→                //load src1
   173→                vP_wt_i8 = __riscv_vle8_v_i8m8_tu(vP_wt_i8, p_wt, vl);
   174→                //load src2
   175→                vint8m8_t vP_in_i8 = __riscv_vle8_v_i8m8(p_in, vl);
   176→                //bump pointers and update loop counter
   177→                colCnt2 -= vl;
   178→                p_wt += vl;
   179→                p_in += vl;
   180→                //set the proper avl/SEW/LMUL values for vd4dot
   181→                //remember to deal with the avl of vd4dot is not a multiple of 4 case
   182→                vl = __riscv_vsetvl_e32m8(vl);
   183→                //acc += src1 * src2
   184→                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8, vP_in_i8, vl);
   185→            }
   186→
   187→            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
   188→            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
   189→
   190→            //add bias back
   191→            vl = __riscv_vsetvl_e32m1(1);
   192→            vint8mf4_t vBias_i8mf4 = __riscv_vle8_v_i8mf4(bias, vl);
   193→            vint32m1_t vBias_i32m1 = __riscv_vsext_vf4(vBias_i8mf4, vl);
   194→            vBias_i32m1 = __riscv_vsll(vBias_i32m1, bias_lshift, vl);
   195→            vBias_i32m1 = __riscv_vadd(vBias_i32m1, NN_ROUND(out_rshift), vl);
   196→            vSum = __riscv_vadd(vSum, vBias_i32m1, vl);
   197→
   198→            //scale down, clip and store the results
   199→            vl = __riscv_vsetvl_e16mf2(1);
   200→            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, out_rshift, vl);
   201→            vl = __riscv_vsetvl_e8mf4(1);
   202→            vint8mf4_t vSum_i8mf4 = __riscv_vnclip(vSum_i16mf2, 0, __RISCV_VXRM_RNU, vl);
   203→            __riscv_vse8(pOut, vSum_i8mf4, vl);
   204→
   205→            bias += vl;
   206→            pOut += vl;
   207→        }
   208→    }
   209→#elif defined(ENA_VEC_ISA_ZVQMAC)
   210→    /* left-over because odd number of output pixels */
   211→    if (pBuffer != (q7_t *)in_tmp_buf)
   212→    {
   213→        const q7_t *pA = ker_weight;
   214→        int i;
   215→        /* basically each time it process 4 entries */
   216→        long colCnt = (3 * ker_dim * ker_dim);
   217→
   218→        //set SEW for 1st time VMV_S_X
   219→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
   220→        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
   221→
   222→        for (i = 0; i < out_tensor_ch; i++)
   223→        {
   224→            q31_t sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
   225→            q7_t *pB = (q7_t*)in_tmp_buf;
   226→            long colCnt2 = colCnt;
   227→
   228→            //init
   229→            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
   230→            //clear v8~v15 (acc)
   231→            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
   232→
   233→            while(colCnt2 > 0)
   234→            {
   235→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
   236→                NDS_VEC_VLB_V(NDS_VEC_V2, pA);
   237→                NDS_VEC_VLB_V(NDS_VEC_V4, pB);
   238→                NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V2, NDS_VEC_V4);
   239→
   240→                //bump pointers and update loop counter
   241→                colCnt2 -= vl;
   242→                pA += vl;
   243→                pB += vl;
   244→            }
   245→
   246→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
   247→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V0);
   248→            //move vr results to gpr
   249→            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);
   250→
   251→            *pOut++ = (q7_t) NDS_ISA_SATS((sum >> out_rshift), 8);
   252→        }
   253→    }
   254→#endif
   255→#elif defined(ENA_VEC_ISA)
   256→    long   i_out_y, i_out_x, i_ker_y, i_ker_x;
   257→
   258→    /*
   259→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
   260→     *  im2col are done to output in q15_t format from q7_t input
   261→     */
   262→    q7_t *pBuffer = (q7_t *)in_tmp_buf;
   263→    q7_t *pOut = out_tensor;
   264→
   265→    long buf_len = (3 * ker_dim * ker_dim + 1);
   266→    long vl;
   267→
   268→    // This part implements the im2col function
   269→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
   270→    {
   271→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
   272→        {
   273→            //init in_tmp_buf
   274→            uint32_t len = buf_len;
   275→            q7_t *pBuffer2 = pBuffer;
   276→            NDS_VEC_VSETVLI_E8(vl, len);
   277→            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //zero
   278→            while(len > 0)
   279→            {
   280→                NDS_VEC_VSB_V(NDS_VEC_V31, pBuffer2);
   281→                len -= vl;
   282→                pBuffer2 += vl;
   283→                NDS_VEC_VSETVLI_E8(vl, len);
   284→            }
   285→
   286→            // if (i_ker_y < 0)
   287→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
   288→            {
   289→                pBuffer += ker_dim * 3;
   290→            }
   291→
   292→            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim)? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
   293→            for (; i_ker_y < bound_y; i_ker_y++)
   294→            {
   295→                // if (i_ker_x < 0)
   296→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
   297→                {
   298→                    pBuffer += 3;
   299→                }
   300→
   301→                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim)? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
   302→                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
   303→                long loop = (bound_x - i_ker_x)*3;
   304→                i_ker_x = bound_x;
   305→                while(loop > 0)
   306→                {
   307→                    NDS_VEC_VSETVLI_E8(vl, loop);
   308→                    NDS_VEC_VLB_V(NDS_VEC_V0, pPixel);
   309→                    NDS_VEC_VSB_V(NDS_VEC_V0, pBuffer);
   310→                    pPixel += vl;
   311→                    pBuffer += vl;
   312→                    loop -= vl;
   313→                }
   314→
   315→                // if (i_ker_x >= in_tensor_dim)
   316→                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
   317→                {
   318→                    pBuffer += 3;
   319→                }
   320→            }
   321→
   322→            // if (i_ker_y >= in_tensor_dim)
   323→            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
   324→            {
   325→                pBuffer += ker_dim * 3;
   326→            }
   327→
   328→            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
   329→            {
   330→                pOut = nn_mat_mul_kernel_q7((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, bias_lshift, out_rshift, bias, pOut);
   331→                pBuffer = (q7_t *)in_tmp_buf;
   332→            }
   333→        }
   334→    }
   335→
   336→#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
   337→    if (pBuffer != (q7_t *)in_tmp_buf)
   338→    {
   339→        unsigned vl;
   340→        const q7_t *p_wt = ker_weight;
   341→        int       i;
   342→        uint16_t  colCnt = 3 * ker_dim * ker_dim;
   343→        // long vlenb = NDS_VEC_CSR_GET_VLENB();
   344→
   345→#if (__clang__)
   346→        register const long zero asm ("x0") = 0;
   347→#else
   348→        register const long zero asm ("x0");
   349→#endif
   350→
   351→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
   352→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum
   353→
   354→        for (i = 0; i < out_tensor_ch; i++)
   355→        {
   356→            q7_t      *p_in = (q7_t*)in_tmp_buf;
   357→            uint16_t colCnt2 = colCnt;
   358→
   359→            //clear v0~v7
   360→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
   361→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
   362→
   363→            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
   364→            // {
   365→            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
   366→            //     //load src1
   367→            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
   368→            //     //load src2
   369→            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
   370→            //     //bump pointers and update loop counter
   371→            //     colCnt2 -= vl;
   372→            //     p_wt += vl;
   373→            //     p_in += vl;
   374→            //     //set the proper avl/SEW/LMUL values for vd4dot
   375→            //     vl >>= 2;
   376→            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
   377→            //     //acc += src1 * src2
   378→            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
   379→            // }
   380→
   381→            //extra process for the case of vd4dot's avl is not a mutiple of 4
   382→            while(colCnt2 > 0)
   383→            {
   384→                //clean one of the dot product source
   385→                NDS_VEC_VSETVLI(vl, zero, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
   386→                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
   387→
   388→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
   389→                //load src1
   390→                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
   391→                //load src2
   392→                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
   393→                //bump pointers and update loop counter
   394→                colCnt2 -= vl;
   395→                p_wt += vl;
   396→                p_in += vl;
   397→                //set the proper avl/SEW/LMUL values for vd4dot
   398→                //remember to deal with the avl of vd4dot is not a multiple of 4 case
   399→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
   400→                //acc += src1 * src2
   401→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
   402→            }
   403→
   404→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
   405→            NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);
   406→
   407→            //add bias back
   408→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
   409→            NDS_VEC_VLB_V(NDS_VEC_V10, bias);
   410→            NDS_VEC_VSEXT_VF4(NDS_VEC_V9, NDS_VEC_V10);
   411→            NDS_VEC_VSLL_VX(NDS_VEC_V9, NDS_VEC_V9, bias_lshift);
   412→            NDS_VEC_VADD_VX(NDS_VEC_V9, NDS_VEC_V9, NN_ROUND(out_rshift));
   413→            NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V9);
   414→
   415→            //scale down, clip and store the results
   416→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
   417→            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, out_rshift);
   418→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
   419→            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
   420→            NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
   421→
   422→            bias += vl;
   423→            pOut += vl;
   424→        }
   425→    }
   426→#elif defined(ENA_VEC_ISA_ZVQMAC)
   427→    /* left-over because odd number of output pixels */
   428→    if (pBuffer != (q7_t *)in_tmp_buf)
   429→    {
   430→        const q7_t *pA = ker_weight;
   431→        int i;
   432→        /* basically each time it process 4 entries */
   433→        long colCnt = (3 * ker_dim * ker_dim);
   434→
   435→        //set SEW for 1st time VMV_S_X
   436→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
   437→        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
   438→
   439→        for (i = 0; i < out_tensor_ch; i++)
   440→        {
   441→            q31_t sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
   442→            q7_t *pB = (q7_t*)in_tmp_buf;
   443→            long colCnt2 = colCnt;
   444→
   445→            //init
   446→            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
   447→            //clear v8~v15 (acc)
   448→            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
   449→
   450→            while(colCnt2 > 0)
   451→            {
   452→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
   453→                NDS_VEC_VLB_V(NDS_VEC_V2, pA);
   454→                NDS_VEC_VLB_V(NDS_VEC_V4, pB);
   455→                NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V2, NDS_VEC_V4);
   456→                //bump pointers and update loop counter
   457→                colCnt2 -= vl;
   458→                pA += vl;
   459→                pB += vl;
   460→            }
   461→
   462→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
   463→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V0);
   464→            //move vr results to gpr
   465→            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);
   466→
   467→            *pOut++ = (q7_t) NDS_ISA_SATS((sum >> out_rshift), 8);
   468→        }
   469→    }
   470→#endif
   471→#elif defined(ENA_DSP_ISA_V5)
   472→    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
   473→
   474→    q7_t *wt_tmp = (q7_t*)ker_weight;
   475→    q7_t    *pBuffer = (q7_t *)in_tmp_buf;
   476→    q7_t     *pOut = out_tensor;
   477→
   478→    uint32_t i;
   479→    q7_t    *pBufferB = (q7_t *)wt_tmp_buf;
   480→
   481→    uint16_t totalsize = 3 * ker_dim * ker_dim;
   482→    for (i = 0; i < out_tensor_ch; i++)
   483→    {
   484→        uint32_t j;
   485→        for (j = 0; j < totalsize; j++)
   486→        {
   487→            *pBufferB++ = *wt_tmp++;
   488→        }
   489→        *pBufferB++ = 0;
   490→    }
   491→
   492→    // This part implements the im2col function
   493→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
   494→    {
   495→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
   496→        {
   497→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
   498→            {
   499→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
   500→                {
   501→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
   502→                    {
   503→                        *pBuffer++ = 0;
   504→                        *pBuffer++ = 0;
   505→                        *pBuffer++ = 0;
   506→                    }
   507→                    else
   508→                    {
   509→                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
   510→                        *pBuffer++ = *pPixel++;
   511→                        *pBuffer++ = *pPixel++;
   512→                        *pBuffer++ = *pPixel++;
   513→                    }
   514→                }
   515→            }
   516→            *pBuffer++ = 0;
   517→
   518→            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
   519→            {
   520→                pOut = nn_mat_mul_kernel_q7((q7_t *)wt_tmp_buf, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, bias_lshift, out_rshift, bias, pOut);
   521→                pBuffer = (q7_t *)in_tmp_buf;
   522→            }
   523→        }
   524→    }
   525→
   526→    /* left-over because odd number of output pixels */
   527→#ifdef ENA_DSP_ISA_64
   528→    if (pBuffer != (q7_t *)in_tmp_buf)
   529→    {
   530→        const q7_t *pA = ker_weight;
   531→        int i;
   532→
   533→        for (i = 0; i < out_tensor_ch; i++)
   534→        {
   535→            long sum = 0;
   536→            q7_t *pB = (q7_t*)in_tmp_buf;
   537→
   538→            /* basically each time it process 8 entries */
   539→            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 3;
   540→
   541→            while (colCnt)
   542→            {
   543→                long inA1, inB1;
   544→                inA1 = *__SIMD64(pA)++;
   545→                inB1 = *__SIMD64(pB)++;
   546→                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
   547→                colCnt--;
   548→            }
   549→
   550→            //sum up the high and low part results (SIMD results)
   551→            sum = (q31_t)(sum >> 32) + (q31_t)sum;
   552→
   553→            colCnt = 3 * ker_dim * ker_dim & 0x7;
   554→            while (colCnt)
   555→            {
   556→                q7_t inA1 = *pA++;
   557→                q7_t inB1 = *pB++;
   558→                sum += inA1 * inB1;
   559→                colCnt--;
   560→            }
   561→
   562→            /* add bias back in to sum */
   563→            sum += ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
   564→
   565→            *pOut++ = NDS_DSP_SATS((sum >> out_rshift), 8);
   566→        }
   567→    }
   568→#else
   569→    if (pBuffer != (q7_t *)in_tmp_buf)
   570→    {
   571→        const q7_t *pA = ker_weight;
   572→        int i;
   573→
   574→        for (i = 0; i < out_tensor_ch; i++)
   575→        {
   576→            long sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
   577→            q7_t *pB = (q7_t*)in_tmp_buf;
   578→
   579→            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
   580→            while (colCnt)
   581→            {
   582→                long inA1, inB1;
   583→                inA1 = *__SIMD32(pA)++;
   584→                inB1 = *__SIMD32(pB)++;
   585→                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
   586→                colCnt--;
   587→            }
   588→
   589→            colCnt = 3 * ker_dim * ker_dim & 0x3;
   590→            while (colCnt)
   591→            {
   592→                q7_t inA1 = *pA++;
   593→                q7_t inB1 = *pB++;
   594→                sum += inA1 * inB1;
   595→                colCnt--;
   596→            }
   597→
   598→            *pOut++ = NDS_DSP_SATS((sum >> out_rshift), 8);
   599→        }
   600→    }
   601→#endif
   602→#elif defined(ENA_DSP_ISA)
   603→    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
   604→
   605→    /*
   606→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
   607→     *  im2col are done to output in q15_t format from q7_t input
   608→     */
   609→    q7_t *wt_tmp = (q7_t*)ker_weight;
   610→    q15_t    *pBuffer = in_tmp_buf;
   611→    q7_t     *pOut = out_tensor;
   612→
   613→    uint32_t i;
   614→    uint16_t size;
   615→    uint16_t size2 = (3 * ker_dim * ker_dim) >> 2;
   616→    q31_t tmp;
   617→    q31_t *pwt2 = (q31_t *)wt_tmp_buf;
   618→    for (i = 0; i < out_tensor_ch; i++)
   619→    {
   620→        size = size2;
   621→        while (size != 0)
   622→        {
   623→            tmp = *__SIMD32(wt_tmp)++;;
   624→            *pwt2++ = NDS_DSP_SUNPKD810(tmp);
   625→            *pwt2++ = NDS_DSP_SUNPKD810(tmp >> 16);
