   629→        q7_t tmp2 = *wt_tmp++;
   630→        *pwt2++ = NDS_DSP_PKBB16(tmp2, tmp1);
   631→        tmp1 = *wt_tmp++;
   632→        *pwt2++ = (u16_t)tmp1;
   633→    }
   634→
   635→    // This part implements the im2col function
   636→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
   637→    {
   638→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
   639→        {
   640→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
   641→            {
   642→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
   643→                {
   644→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
   645→                    {
   646→                        *pBuffer++ = 0;
   647→                        *pBuffer++ = 0;
   648→                        *pBuffer++ = 0;
   649→                    }
   650→                    else
   651→                    {
   652→                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
   653→                        *pBuffer++ = *pPixel++;
   654→                        *pBuffer++ = *pPixel++;
   655→                        *pBuffer++ = *pPixel++;
   656→                    }
   657→                }
   658→            }
   659→            *pBuffer++ = 0;
   660→
   661→            if (pBuffer == in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
   662→            {
   663→                pOut = nn_mat_mul_kernel_q15(wt_tmp_buf, in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, bias_lshift, out_rshift, bias, pOut);
   664→                pBuffer = in_tmp_buf;
   665→            }
   666→        }
   667→    }
   668→
   669→    if (pBuffer != in_tmp_buf)
   670→    {
   671→        const q7_t *pA = ker_weight;
   672→        int       i;
   673→
   674→        for (i = 0; i < out_tensor_ch; i++)
   675→        {
   676→            q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
   677→            q15_t    *pB = in_tmp_buf;
   678→
   679→            /* basically each time it process 4 entries */
   680→            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
   681→
   682→            while (colCnt)
   683→            {
   684→
   685→                q31_t     inA1, inA2;
   686→                q31_t     inB1, inB2;
   687→
   688→                pA = (q7_t *) read_and_pad((void *)pA, &inA1, &inA2);
   689→                inB1 = *__SIMD32(pB)++;
   690→                sum = NDS_DSP_KMADA(sum, inA1, inB1);
   691→                inB2 = *__SIMD32(pB)++;
   692→                sum = NDS_DSP_KMADA(sum, inA2, inB2);
   693→
   694→                colCnt--;
   695→            }
   696→            colCnt = 3 * ker_dim * ker_dim & 0x3;
   697→            while (colCnt)
   698→            {
   699→                q7_t      inA1 = *pA++;
   700→                q15_t     inB1 = *pB++;
   701→                sum += inA1 * inB1;
   702→                colCnt--;
   703→            }
   704→            *pOut++ = (q7_t) NDS_DSP_SATS((sum >> out_rshift), 8);
   705→        }
   706→    }
   707→#else
   708→    uint16_t  i, j, k, l, m, n;
   709→    int       conv_out;
   710→    long in_row, in_col;
   711→
   712→    for (i = 0; i < out_tensor_ch; i++)
   713→    {
   714→        for (j = 0; j < out_tensor_dim; j++)
   715→        {
   716→            for (k = 0; k < out_tensor_dim; k++)
   717→            {
   718→                conv_out = (bias[i] << bias_lshift) + NN_ROUND(out_rshift);
   719→                for (m = 0; m < ker_dim; m++)
   720→                {
   721→                    for (n = 0; n < ker_dim; n++)
   722→                    {
   723→                        /* if-for implementation */
   724→                        in_row = stride * j + m - pad;
   725→                        in_col = stride * k + n - pad;
   726→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
   727→                        {
   728→                            for (l = 0; l < 3; l++)
