   731→                                    in_tensor[(in_row * in_tensor_dim + in_col) * 3 + l]
   732→                                    * ker_weight[i * 3 * ker_dim * ker_dim + (m * ker_dim + n) * 3 + l];
   733→                            }
   734→                        }
   735→                    }
   736→                }
