/** @file*/

#include "internal_nn_math.h"

//// Convolution Functions

#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
q7_t *nn_mat_mul_kernel_q7_unroll4(const q7_t * src1,
                                   const q7_t * src2,
                                   const uint16_t out_tensor_ch,
                                   const uint16_t col_src1,
                                   const uint16_t bias_lshift,
                                   const uint16_t out_rshift,
                                   const q7_t * bias,
                                   q7_t * out)
{
#if defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
    unsigned long vl;
    unsigned long rowCnt = out_tensor_ch >> 2;
    q7_t *pOut2 = out + out_tensor_ch;
    q7_t *pOut3 = out + out_tensor_ch * 2;
    q7_t *pOut4 = out + out_tensor_ch * 3;

    const q7_t *pA = src1;

#if (__clang__)
    register const long zero asm ("x0") = 0;
#else
    register const long zero asm ("x0");
#endif
    vl = __riscv_vsetvl_e32m1(1);
    vint32m1_t vZero = __riscv_vundefined_i32m1();
    vZero = __riscv_vand_tu(vZero, vZero, zero, vl);    //const zero for redsum

    while(rowCnt > 0)
    {
        // setup pointers for A
        const q7_t *pA2 = pA + col_src1;
        const q7_t *pA3 = pA + col_src1 * 2;
        const q7_t *pA4 = pA + col_src1 * 3;
        // setup pointers for B
        const q7_t *pB = src2;
        const q7_t *pB2 = pB + col_src1;
        const q7_t *pB3 = pB + col_src1 * 2;
        const q7_t *pB4 = pB + col_src1 * 3;

        vl = __riscv_vsetvlmax_e32m1();
        vint32m1_t vAcc0 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc1 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc2 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc3 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc4 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc5 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc6 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc7 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc8 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc9 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc10 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc11 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc12 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc13 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc14 = __riscv_vundefined_i32m1();
        vint32m1_t vAcc15 = __riscv_vundefined_i32m1();

        //init
        //clear v8~v23 (keep multiplication results)
        vAcc0 = __riscv_vand_tu(vAcc0, vAcc0, zero, vl);
        vAcc1 = __riscv_vand_tu(vAcc1, vAcc1, zero, vl);
        vAcc2 = __riscv_vand_tu(vAcc2, vAcc2, zero, vl);
        vAcc3 = __riscv_vand_tu(vAcc3, vAcc3, zero, vl);
        vAcc4 = __riscv_vand_tu(vAcc4, vAcc4, zero, vl);
        vAcc5 = __riscv_vand_tu(vAcc5, vAcc5, zero, vl);
        vAcc6 = __riscv_vand_tu(vAcc6, vAcc6, zero, vl);
        vAcc7 = __riscv_vand_tu(vAcc7, vAcc7, zero, vl);
        vAcc8 = __riscv_vand_tu(vAcc8, vAcc8, zero, vl);
        vAcc9 = __riscv_vand_tu(vAcc9, vAcc9, zero, vl);
        vAcc10 = __riscv_vand_tu(vAcc10, vAcc10, zero, vl);
        vAcc11 = __riscv_vand_tu(vAcc11, vAcc11, zero, vl);
        vAcc12 = __riscv_vand_tu(vAcc12, vAcc12, zero, vl);
        vAcc13 = __riscv_vand_tu(vAcc13, vAcc13, zero, vl);
        vAcc14 = __riscv_vand_tu(vAcc14, vAcc14, zero, vl);
